import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';
import './Auth.css';

const Login = () => {
  const [formData, setFormData] = useState({ email: '', password: '' });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleChange = (e) => {
    setFormData((prev) => ({ ...prev, [e.target.name]: e.target.value }));
    setError('');
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!formData.email.trim() || !formData.password) {
      setError('Please enter your email and password.');
      return;
    }
    try {
      setLoading(true);
      const { data } = await axios.post('/api/auth/login', formData);
      login(data.user, data.token);
      navigate('/', { replace: true });
    } catch (err) {
      setError(err.response?.data?.message || 'Login failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="auth-page">
      {/* Left Brand Panel */}
      <div className="auth-left">
        <div className="auth-left-blob auth-left-blob-1" />
        <div className="auth-left-blob auth-left-blob-2" />
        <div className="auth-brand">
          <div className="auth-brand-logo">💙 Fund<span>It</span></div>
          <div className="auth-brand-tagline">Changing lives, one rupee at a time.</div>
        </div>
        <div className="auth-testimonial">
          <p className="auth-testimonial-text">
            "FundIt helped us raise ₹8 lakhs for my father's heart surgery in just 3 days.
            The response was overwhelming. I'm forever grateful."
          </p>
          <div className="auth-testimonial-author">
            <div className="auth-testimonial-avatar">R</div>
            <div>
              <div className="auth-testimonial-name">Riya Sharma</div>
              <div className="auth-testimonial-role">Delhi — Campaign Recipient</div>
            </div>
          </div>
        </div>
      </div>

      {/* Right Form Panel */}
      <div className="auth-right">
        <div className="auth-form-wrapper" id="login-form-container">
          <div className="auth-form-header">
            <Link to="/" className="auth-back-link" id="back-to-home">
              ← Back to campaigns
            </Link>
            <h1 className="auth-form-title">Welcome back</h1>
            <p className="auth-form-subtitle">Sign in to your FundIt account to continue making an impact.</p>
          </div>

          {error && (
            <div className="alert alert-error" id="login-error-alert" role="alert">
              <span>⚠️</span>
              <p>{error}</p>
            </div>
          )}

          <form onSubmit={handleSubmit} noValidate id="login-form">
            <div className="form-group">
              <label className="form-label" htmlFor="login-email">Email Address</label>
              <input
                id="login-email"
                name="email"
                type="email"
                className="form-input"
                placeholder="you@example.com"
                value={formData.email}
                onChange={handleChange}
                autoComplete="email"
                required
              />
            </div>

            <div className="form-group">
              <label className="form-label" htmlFor="login-password">Password</label>
              <input
                id="login-password"
                name="password"
                type="password"
                className="form-input"
                placeholder="Enter your password"
                value={formData.password}
                onChange={handleChange}
                autoComplete="current-password"
                required
              />
            </div>

            <button
              type="submit"
              className="auth-submit-btn"
              disabled={loading}
              id="btn-login-submit"
            >
              {loading ? <><span className="spinner" />Signing in...</> : 'Sign In to FundIt'}
            </button>
          </form>

          <div className="auth-footer">
            <p>
              Don't have an account?{' '}
              <Link to="/register" id="link-to-register">Create a free account</Link>
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Login;
